    func visitFigureStart(_ ctx: NodeContext) -> VisitResult
    func visitFigcaption(_ ctx: NodeContext, _ text: String) -> VisitResult
    func visitFigureEnd(_ ctx: NodeContext, _ output: String) -> VisitResult
}

